fn test_attack_push_promise_flood() {
    init_test_logging();

    let config = ClientConfig {
        enable_push: true,
        max_concurrent_streams: 100,
    };
    let mut client = H2Client::new(config);

    // Simulate malicious server sending flood of PUSH_PROMISE
    let mut accepted = 0;
    let mut rejected = 0;

    for i in 0..10000 {
        let promised_id = (i + 1) * 2; // Even IDs
        let result = client.receive_push_promise(
            /*associated_stream=*/ 1,
            /*promised_stream=*/ promised_id,
            &[/* minimal headers */],
        );

        match result {
            Ok(_) => accepted += 1,
            Err(H2Error::RefusedStream(_)) => rejected += 1,
            Err(e) => panic!("unexpected error: {:?}", e),
        }
    }

    assert_eq!(accepted, 100, "should accept up to max_concurrent_streams");
    assert_eq!(rejected, 9900, "should reject the rest");
    assert!(client.memory_usage() < 10_000_000, "memory bounded");
